import { _decorator, Component, director, Node, Label, Button, ProgressBar } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('ThunderScene')
export class ThunderScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    startBtn: Button = null;
    
    @property(Label)
    statusLabel: Label = null;
    
    @property(Label)
    thunderCountLabel: Label = null;
    
    @property(Label)
    currentBuffLabel: Label = null;
    
    @property(ProgressBar)
    healthBar: ProgressBar = null;
    
    @property(Label)
    riskWarningLabel: Label = null;
    
    private thunderCount = 0;
    private maxThunders = 18;
    private isActive = false;
    private health = 100;
    private buffs = [];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.startBtn.node.on(Button.EventType.CLICK, this.onStart, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        this.thunderCountLabel.string = `已承受雷击: ${this.thunderCount}/${this.maxThunders}`;
        this.currentBuffLabel.string = `当前加成:\n${this.getBuffText()}`;
        this.healthBar.progress = this.health / 100;
        
        if (this.health <= 0) {
            this.statusLabel.string = '已死亡，损失10%修为';
            this.statusLabel.color = {r: 255, g: 0, b: 0, a: 255};
        } else if (this.thunderCount >= this.maxThunders) {
            this.statusLabel.string = '✅ 完成18道雷击，获得永久突破！';
            this.statusLabel.color = {r: 0, g: 255, b: 0, a: 255};
        } else if (this.isActive) {
            this.statusLabel.string = '⚡ 雷电淬炼中...';
        } else {
            this.statusLabel.string = '准备开始雷电淬炼';
        }
    }
    
    getBuffText(): string {
        if (this.buffs.length === 0) return '无';
        return this.buffs.map(b => `${b.name} +${b.value}`).join('\n');
    }
    
    onStart() {
        if (this.isActive || this.health <= 0 || this.thunderCount >= this.maxThunders) return;
        
        this.isActive = true;
        this.statusLabel.string = '⚡ 雷电淬炼开始！';
        
        // 开始雷击循环
        this.schedule(this.onThunderStrike, 3);
    }
    
    onThunderStrike() {
        if (this.health <= 0 || this.thunderCount >= this.maxThunders) {
            this.unschedule(this.onThunderStrike);
            this.isActive = false;
            return;
        }
        
        this.thunderCount++;
        
        // 计算伤害
        const damage = 5 + this.thunderCount * 2;
        this.health -= damage;
        
        // 随机获得临时加成
        if (this.health > 0) {
            const buffs = [
                { name: '攻击', value: Math.floor(Math.random() * 50) + 10 },
                { name: '防御', value: Math.floor(Math.random() * 30) + 5 },
                { name: '暴击', value: Math.floor(Math.random() * 10) + 2 }
            ];
            const buff = buffs[Math.floor(Math.random() * buffs.length)];
            this.buffs.push(buff);
            
            // 第18道雷击获得永久突破
            if (this.thunderCount === 18) {
                alert('🎉 恭喜！获得永久属性突破！');
                GameManager.getInstance().playerData.addCurrency('cultivation', 1000);
            }
        } else {
            // 死亡惩罚
            alert('💀 承受不住雷击，死亡！损失10%修为');
            GameManager.getInstance().playerData.costCurrency('cultivation', 100);
        }
        
        this.updateUI();
    }
    
    onBack() {
        this.unscheduleAllCallbacks();
        director.loadScene('MainScene');
    }
    
    onDestroy() {
        this.unscheduleAllCallbacks();
    }
}
